import { useParams, useNavigate } from "react-router-dom";
import { blogData } from "../data/blogData";
import { slugify } from "../utils/slugify";

const BlogDetails = () => {
  const { slug } = useParams<{ slug: string }>();
  const navigate = useNavigate();
  const blog = blogData.find((b) => slugify(b.title) === slug);

  if (!blog) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-gray-900 text-white">
        <h1 className="text-4xl font-bold mb-4">404 - Blog Not Found</h1>
        <button
          onClick={() => navigate("/blogs")}
          className="px-6 py-3 bg-lime-600 rounded-lg hover:bg-lime-700 transition-colors"
        >
          Back to Blogs
        </button>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-900 text-white py-16 px-4 sm:px-6 lg:px-8">
      <div className="max-w-4xl mx-auto">
        {/* Back Button */}
        <button
          onClick={() => navigate(-1)}
          className="flex items-center text-lime-400 hover:text-lime-300 mb-8 transition-colors"
        >
          <svg
            xmlns="http://www.w3.org/2000/svg"
            className="h-5 w-5 mr-2"
            viewBox="0 0 20 20"
            fill="currentColor"
          >
            <path
              fillRule="evenodd"
              d="M9.707 16.707a1 1 0 01-1.414 0l-6-6a1 1 0 010-1.414l6-6a1 1 0 011.414 1.414L5.414 9H17a1 1 0 110 2H5.414l4.293 4.293a1 1 0 010 1.414z"
              clipRule="evenodd"
            />
          </svg>
          Back to Blogs
        </button>

        {/* Blog Content */}
        <div className="bg-gray-800 rounded-xl overflow-hidden shadow-2xl">
          {/* Blog Image */}
          <div className="relative h-64 sm:h-80 md:h-96">
            <img
              src={blog.image}
              alt={blog.title}
              className="w-full h-full object-cover"
            />
            {/* Category Badge */}
            <span className="absolute top-4 left-4 bg-black/80 text-white px-3 py-1 rounded-lg text-sm font-medium capitalize">
              {blog.category}
            </span>
          </div>

          {/* Blog Text Content */}
          <div className="p-6 sm:p-8">
            <div className="flex justify-between items-start mb-6">
              <div>
                <h1 className="text-3xl sm:text-4xl font-bold mb-2">
                  {blog.title}
                </h1>
                <p className="text-gray-300">{blog.description}</p>
              </div>
              <div className="text-right">
                <p className="text-sm text-gray-400">{blog.date}</p>
                <p className="text-sm text-gray-400">{blog.readTime}</p>
              </div>
            </div>

            {/* Author Info */}
            <div className="flex items-center mb-8">
              <div className="w-10 h-10 rounded-full bg-gray-700 flex items-center justify-center mr-3">
                <span className="text-lg">
                  {blog.author
                    .split(" ")
                    .map((n) => n[0])
                    .join("")}
                </span>
              </div>
              <div>
                <p className="font-medium">{blog.author}</p>
                <p className="text-sm text-gray-400">Business Consultant</p>
              </div>
            </div>

            {/* Blog Content */}
            <div className="prose prose-invert max-w-none">
              {blog.content.map((paragraph, index) => (
                <p key={index} className="mb-4 text-gray-300">
                  {paragraph}
                </p>
              ))}
            </div>

            {/* Tags */}
            <div className="mt-12 pt-6 border-t border-gray-700">
              <div className="flex flex-wrap gap-2">
                {["Business", "Management", "Technology", "Strategy"].map(
                  (tag) => (
                    <span
                      key={tag}
                      className="px-3 py-1 bg-gray-700 rounded-full text-sm"
                    >
                      {tag}
                    </span>
                  )
                )}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default BlogDetails;
